mapper.select:
SELECT DISTINCT Row_Number()OVER(ORDER BY TI.Identifier, TI.ClassCode) as RNUM , TI.ItemID , ISNULL(TIA.PlainText,'') AS ItemName , TD.Name as ClassName , TI.ClassCode , TI.Identifier , TITO.SortNum , TITO.CategoryCode , TI.Status As Status , TSD.Name As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}) AS getPath , ISNULL(TMT.Name, '') AS TeamName , ISNULL(TOT.Name,'') AS OwnerTeamName , ISNULL(TM.Name,'') AS Name , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , TI.Version
, TIA4.PlainText AS guideline , TATL5.Value AS systemType , TIA6.PlainText AS modualAPP , TIA7.PlainText AS fioriID , TIA8.PlainText AS tCode , TIA9.PlainText AS chkPoint , TIA10.PlainText AS role , TIA11.PlainText AS relOrg , TIA12.PlainText AS issue , TIA13.PlainText AS funcReq , TIA14.PlainText AS businessRule , TIA15.PlainText AS legacy , TIA16.PlainText AS legacyIFID , TM.Name AS AuthorID FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TITO ON TITO.ToITemID = TI.ItemID And TITO.CategoryCode = 'ST1' And TITO.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 on TI.ItemID = TIA4.ItemID AND TIA4.AttrTypeCode = 'AT00008' AND TIA4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 on TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'AT00037' AND TIA5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL5 on TIA5.AttrTypeCode = TATL5.AttrTypeCode AND TIA5.LovCode = TATL5.LovCode AND TIA5.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 on TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'AT00013' AND TIA6.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA7 on TI.ItemID = TIA7.ItemID AND TIA7.AttrTypeCode = 'AT00039' AND TIA7.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 on TI.ItemID = TIA8.ItemID AND TIA8.AttrTypeCode = 'AT00014' AND TIA8.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA9 on TI.ItemID = TIA9.ItemID AND TIA9.AttrTypeCode = 'AT00029' AND TIA9.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 on TI.ItemID = TIA10.ItemID AND TIA10.AttrTypeCode = 'AT00010' AND TIA10.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA11 on XBOLTADM.fn_GetParentItemID(TI.ItemID,4) = TIA11.ItemID AND TIA11.AttrTypeCode = 'AT00017' AND TIA11.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA12 on TI.ItemID = TIA12.ItemID AND TIA12.AttrTypeCode = 'AT00006' AND TIA12.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA13 on TI.ItemID = TIA13.ItemID AND TIA13.AttrTypeCode = 'AT00048' AND TIA13.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA14 on TI.ItemID = TIA14.ItemID AND TIA14.AttrTypeCode = 'AT00042' AND TIA14.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode
LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.LanguageID = #{languageID} AND TMT.TeamID = TI.CompanyID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TOT.LanguageID = #{languageID} AND TOT.TeamID = TI.OwnerTeamID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TSD.LanguageID = #{languageID} AND TSD.TypeCode = TI.Status AND TSD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA15 on TI.ItemID = TIA15.ItemID AND TIA15.AttrTypeCode = 'ZAT0014' AND TIA15.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA16 on TI.ItemID = TIA16.ItemID AND TIA16.AttrTypeCode = 'ZAT0015' AND TIA16.LanguageID = #{languageID} WHERE TI.Deleted != 1 AND TI.ItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'ST1') Order by TITO.SortNum ASC

SELECT TI.ItemID , TIA1.PlainText AS ItemName , CASE WHEN TI.CategoryCode = 'REF' THEN ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TIA2.ItemID , #{languageID} ),'')+'/'+ TIA2.PlainText WHEN TI.CategoryCode IN('MCN', 'CN', 'CN1') THEN ISNULL(TIAF.PlainText,'') + ' --> ' + ISNULL(TIAT.PlainText,'') ELSE ISNULL(XBOLTADM.fn_GetMyAbsPathForList( #{s_itemID} ,#{languageID} ),'') END AS Path , TD.Name as ClassName , TDI.Name as ItemTypeName , TT.Name as TeamName , TOT.Name as OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS Name , CONVERT(VARCHAR, TI.CreationTime, 111) AS CreateDT , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , TCS.Version , TI.Identifier , TI.AuthorID AS AuthorID , TI.LockOwner AS LockOwner , TI.OwnerTeamID , TIA3.PlainText AS Description , TI.ClassCode AS ClassCode , TI.Level AS Level , Case When TI.Deleted = 1 Then TD2.Name + '(Deleted)' Else TD2.Name END As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , (Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} And CategoryCode = 'ST1') AS FromItemID , TPT.Name AS ProjectName , TPT2.Name As RefPjtName , TI.ProjectID AS ProjectID , TI.CurChangeSet , TI.ReleaseNo , TI.Status , TI.Blocked , ISNULL(TITF.Icon, 'img_job.png') FromItemTypeImg , ISNULL(TITT.Icon, 'img_job.png') ToItemTypeImg , LTRIM(RTRIM(TI.CategoryCode)) AS CategoryCode , ISNULL(TIAF.PlainText,'') AS FromItemName , ISNULL(TIAT.PlainText,'') AS ToItemName , TCL.CheckOutOption , TCS.CheckInOption , TCS.Reason , TCS.Description AS ChangeSetDec , ISNULL(CONVERT(char(10), TCS.CompletionDT, 111),'-') as CompletionDT , TCL.SubscrOption , TCL.ChangeMgt , ISNULL(TM.Name,'') AS AuthorName , TI.ItemTypeCode , TCS.WFInstanceID , Convert(nvarchar(20),ISNULL(TCS.ValidFrom,TI.LastUpdated), 111) AS ValidFrom , STUFF(( SELECT '/' + convert(nvarchar, B.NAME) FROM XBOLTADM.TB_ITEM_DIM A inner join XBOLTADM.TB_DIM_VALUE_TXT B ON A.DimTypeID = B.DimTypeID and A.DimValueID = B.DimValueID and B.LanguageID = #{languageID} WHERE A.ItemID = TI.ItemID AND A.DimTypeID = '100003' FOR XML PATH('') ), 1, 1, '') AS DimValueIDs ,(select case when count(*) > 0 then 'O' else '' end from XBOLTADM.TB_ITEM_DIM WHERE ItemID = (select FROMitemID from XBOLTADM.TB_ITEM where ToItemID = Ti.ItemID and ItemTypeCode = 'CN00001') and DimTypeID = '100003' and DimValueID = 'C101') AS C101 ,(select case when count(*) > 0 then 'O' else '' end from XBOLTADM.TB_ITEM_DIM WHERE ItemID = (select FROMitemID from XBOLTADM.TB_ITEM where ToItemID = Ti.ItemID and ItemTypeCode = 'CN00001') and DimTypeID = '100003' and DimValueID = 'C102') AS C102
FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 on TI.ItemID = TIA1.ItemID AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 on TI.RefItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00001' AND TIA2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 on TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'AT00003' AND TIA3.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD2 on TI.Status = TD2.TypeCode AND TD2.Category = 'ITMSTS' AND TD2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_PROJECT TP ON TP.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT On TPT.ProjectID = TI.ProjectID And TPT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT2 On TPT2.ProjectID = TP.RefPjtID And TPT2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAF ON TIAF.ItemID IN(Select FromItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAF.AttrTypeCode = 'AT00001' And TIAF.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAT ON TIAT.ItemID IN(Select ToItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAT.AttrTypeCode = 'AT00001' And TIAT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITF ON TITF.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.FromItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITT ON TITT.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.ToItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCL ON TCL.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ChangeSetID = TI.CurChangeSet LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDI on TI.ItemTypeCode = TDI.TypeCode AND TDI.LanguageID = #{languageID}
WHERE TI.ItemID = #{s_itemID}

SELECT TI.ItemID , TIA1.PlainText AS ItemName , CASE WHEN TI.CategoryCode = 'REF' THEN ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TIA2.ItemID , #{languageID} ),'')+'/'+ TIA2.PlainText WHEN TI.CategoryCode IN('MCN', 'CN', 'CN1') THEN ISNULL(TIAF.PlainText,'') + ' --> ' + ISNULL(TIAT.PlainText,'') ELSE ISNULL(XBOLTADM.fn_GetMyAbsPathForList( #{s_itemID} ,#{languageID} ),'') END AS Path , TD.Name as ClassName , TDI.Name as ItemTypeName , TT.Name as TeamName , TOT.Name as OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS Name , CONVERT(VARCHAR, TI.CreationTime, 111) AS CreateDT , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , TCS.Version , TI.Identifier , TI.AuthorID AS AuthorID , TI.LockOwner AS LockOwner , TI.OwnerTeamID , TIA3.PlainText AS Description , TI.ClassCode AS ClassCode , TI.Level AS Level , Case When TI.Deleted = 1 Then TD2.Name + '(Deleted)' Else TD2.Name END As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , (Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} And CategoryCode = 'ST1') AS FromItemID , TPT.Name AS ProjectName , TPT2.Name As RefPjtName , TI.ProjectID AS ProjectID , TI.CurChangeSet , TI.ReleaseNo , TI.Status , TI.Blocked , ISNULL(TITF.Icon, 'img_job.png') FromItemTypeImg , ISNULL(TITT.Icon, 'img_job.png') ToItemTypeImg , LTRIM(RTRIM(TI.CategoryCode)) AS CategoryCode , ISNULL(TIAF.PlainText,'') AS FromItemName , ISNULL(TIAT.PlainText,'') AS ToItemName , TCL.CheckOutOption , TCS.CheckInOption , TCS.Reason , TCS.Description AS ChangeSetDec , ISNULL(CONVERT(char(10), TCS.CompletionDT, 111),'-') as CompletionDT , TCL.SubscrOption , TCL.ChangeMgt , ISNULL(TM.Name,'') AS AuthorName , TI.ItemTypeCode , TCS.WFInstanceID , Convert(nvarchar(20),ISNULL(TCS.ValidFrom,TI.LastUpdated), 111) AS ValidFrom , STUFF(( SELECT '/' + convert(nvarchar, B.NAME) FROM XBOLTADM.TB_ITEM_DIM A inner join XBOLTADM.TB_DIM_VALUE_TXT B ON A.DimTypeID = B.DimTypeID and A.DimValueID = B.DimValueID and B.LanguageID = #{languageID} WHERE A.ItemID = TI.ItemID AND A.DimTypeID = '100003' FOR XML PATH('') ), 1, 1, '') AS DimValueIDs ,(select case when count(*) > 0 then 'O' else '' end from XBOLTADM.TB_ITEM_DIM WHERE ItemID = (select FROMitemID from XBOLTADM.TB_ITEM where ToItemID = Ti.ItemID and ItemTypeCode = 'CN00001') and DimTypeID = '100200' and DimValueID = 'BC01') AS C101 ,(select case when count(*) > 0 then 'O' else '' end from XBOLTADM.TB_ITEM_DIM WHERE ItemID = (select FROMitemID from XBOLTADM.TB_ITEM where ToItemID = Ti.ItemID and ItemTypeCode = 'CN00001') and DimTypeID = '100200' and DimValueID = 'BC02') AS C102
FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 on TI.ItemID = TIA1.ItemID AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 on TI.RefItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00001' AND TIA2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 on TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'AT00003' AND TIA3.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD2 on TI.Status = TD2.TypeCode AND TD2.Category = 'ITMSTS' AND TD2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_PROJECT TP ON TP.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT On TPT.ProjectID = TI.ProjectID And TPT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT2 On TPT2.ProjectID = TP.RefPjtID And TPT2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAF ON TIAF.ItemID IN(Select FromItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAF.AttrTypeCode = 'AT00001' And TIAF.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAT ON TIAT.ItemID IN(Select ToItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAT.AttrTypeCode = 'AT00001' And TIAT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITF ON TITF.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.FromItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITT ON TITT.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.ToItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCL ON TCL.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ChangeSetID = TI.CurChangeSet LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDI on TI.ItemTypeCode = TDI.TypeCode AND TDI.LanguageID = #{languageID}
WHERE TI.ItemID = #{s_itemID}

SELECT DISTINCT Row_Number()OVER(ORDER BY TI.Identifier, TI.ClassCode) as RNUM , TI.ItemID , ISNULL(TIA.PlainText,'') AS ItemName , TD.Name as ClassName , TI.ClassCode , TI.Identifier , TITO.SortNum , TITO.CategoryCode , TI.Status As Status , TSD.Name As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}) AS getPath , ISNULL(TMT.Name, '') AS TeamName , ISNULL(TOT.Name,'') AS OwnerTeamName , ISNULL(TM.Name,'') AS Name , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , TI.Version
, TIA4.PlainText AS description , TATL5.Value AS ApplicationType , TIA6.PlainText AS tCode , TIA7.PlainText AS IpMethod , TIA8.PlainText AS RsEntity , TIA9.PlainText AS System , TM.Name AS AuthorID FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TITO ON TITO.ToITemID = TI.ItemID And TITO.CategoryCode = 'ST1' And TITO.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 on TI.ItemID = TIA4.ItemID AND TIA4.AttrTypeCode = 'AT00003' AND TIA4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 on TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'AT00037' AND TIA5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL5 on TIA5.AttrTypeCode = TATL5.AttrTypeCode AND TIA5.LovCode = TATL5.LovCode AND TIA5.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 on TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'AT00014' AND TIA6.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA7 on TI.ItemID = TIA7.ItemID AND TIA7.AttrTypeCode = 'AT00049' AND TIA7.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 on TI.ItemID = TIA8.ItemID AND TIA8.AttrTypeCode = 'AT00017' AND TIA8.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA9 on TI.ItemID = TIA9.ItemID AND TIA9.AttrTypeCode = 'AT00013' AND TIA9.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode
LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.LanguageID = #{languageID} AND TMT.TeamID = TI.CompanyID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TOT.LanguageID = #{languageID} AND TOT.TeamID = TI.OwnerTeamID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TSD.LanguageID = #{languageID} AND TSD.TypeCode = TI.Status AND TSD.Category = 'ITMSTS' WHERE TI.Deleted != 1 AND TI.ItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'ST1') Order by TITO.SortNum ASC
